import React from "react";
import Grid from "@material-ui/core/Grid";
import { makeStyles } from "@material-ui/core/styles";
import Typography from "@material-ui/core/Typography";
import Box from "@material-ui/core/Box";
import fondo from "../img/fondo.jpg";
import { useTranslation } from "react-i18next";

const useStyles = makeStyles((theme) => ({
  root: {
    justifyContent: "space-around",
    margin: theme.spacing(10, 0, 10, 0),
    boxShadow: theme.shadows[5],
  },
  paper: {
    padding: theme.spacing(5),
    backgroundColor: "#e0fbfc",
  },
  imag: {
    backgroundImage: `url(${fondo})`,
    backgroundSize: "cover",
    backgroundPosition: "center center",
  },
  content: {
    padding: theme.spacing(1),
    marginTop: theme.spacing(1),
  },
  table: {
    display: "flex",
    justifyContent: "space-evenly",
    textAlign: "left",
    alignItems: "center",
  },
  tableth: {
    fontSize: "1.2rem",
    color: "#0c0f0a",
    margin: theme.spacing(0.5, 0),
    width: "25%",
  },
  tabletd: {
    fontSize: "1.2rem",
    color: "#0c0f0a",
    width: "70%",
  },

  titulo: {
    fontWeight: 900,
    textAlign: "center",
    marginTop: theme.spacing(10),
  },
  subtitulo: {
    textAlign: "center",
  },

  textCont: {
    padding: theme.spacing(0.4),
    boxShadow: theme.shadows[5],
    backgroundColor: "#0c0f0a",
    margin: theme.spacing(5, 0),
  },
  text: {
    fontWeight: 900,
    margin: theme.spacing(1, 2),
    color: "#e0fbfc",
  },
  text1: {
    fontWeight: 900,
    margin: theme.spacing(1, 2),
    color: "#e0fbfc",
  },
}));
function About() {
  const classes = useStyles();
  const [t] = useTranslation("global");
  return (
    <React.Fragment>
      <Typography variant="h2" color="secondary" className={classes.titulo}>
        {t("Presentación.Contacto")}
      </Typography>
      <Typography
        variant="h5"
        id={"information"}
        color="secondary"
        className={classes.subtitulo}
      >
        {t("Presentación.Información")}
      </Typography>
      <Grid container className={classes.root}>
        <Grid item xs={12} sm={7} className={classes.paper}>
          <Box
            className={classes.textCont}
            data-aos="flip-up"
            data-aos-duration="2000"
          >
            <Typography variant="h4" className={classes.text1} gutterBottom>
              {t("Presentación.Básico")}
            </Typography>
            <Typography variant="h4" className={classes.text} gutterBottom>
              {t("Presentación.Información1")}
            </Typography>
          </Box>
          <Box className={classes.content}>
            <div className={classes.table}>
              <span className={classes.tableth}>{t("Presentación.EDAD")}:</span>
              <span className={classes.tabletd}>33</span>
            </div>
            <div className={classes.table}>
              <span className={classes.tableth}>EMAIL:</span>
              <span className={classes.tabletd}>codigoarchivo@gmail.com</span>
            </div>
            <div className={classes.table}>
              <span className={classes.tableth}>
                {t("Presentación.TELÉFONO")}:
              </span>
              <span className={classes.tabletd}>+584126804788</span>
            </div>
            <div className={classes.table}>
              <span className={classes.tableth}>
                {t("Presentación.DIRECCIÓN")}:
              </span>
              <span className={classes.tabletd}>Trujillo, Venezuela</span>
            </div>
            <div className={classes.table}>
              <span className={classes.tableth}>
                {t("Presentación.IDIOMA")}:
              </span>
              <span className={classes.tabletd}>
                {t("Presentación.BásicoAvanzado")}
              </span>
            </div>
          </Box>
        </Grid>
        <Grid item xs={12} sm={5} className={classes.imag}></Grid>
      </Grid>
    </React.Fragment>
  );
}
export default About;
