import React from "react";
import { makeStyles } from "@material-ui/core/styles";
import Typography from "@material-ui/core/Typography";
import Grid from "@material-ui/core/Grid";

import Card from "@material-ui/core/Card";
import CardHeader from "@material-ui/core/CardHeader";
import CardContent from "@material-ui/core/CardContent";
import CardActions from "@material-ui/core/CardActions";
import Avatar from "@material-ui/core/Avatar";
import IconButton from "@material-ui/core/IconButton";

import ShareIcon from "@material-ui/icons/Share";
import uvm from "../img/uvm.png";
import { useTranslation } from "react-i18next";
import "../index.css";

const useStyles = makeStyles((theme) => ({
  root: {
    display: "flex",
    justifyContent: "center",
    margin: theme.spacing(10, 0),
    padding: theme.spacing(5, 0),
    backgroundColor: "#e0fbfc",
    boxShadow: theme.shadows[5],
    color: "#e0fbfc",
  },
  titulo: {
    fontWeight: 900,
    textAlign: "center",
  },
  subtitulo: {
    textAlign: "center",
  },
  subtitulo1: {
    textAlign: "center",
    margin: theme.spacing(4, 0),
  },

  card: {
    backgroundColor: "#e0fbfc",
  },
  item: {
    margin: theme.spacing(6, 0),
  },
  avatar: {
    width: "100%",
    backgroundColor: "#0c0f0a",
    color: "#e0fbfc",
  },
  parrafo: {
    fontSize: "1.2rem",
    padding: theme.spacing(0, 3),
    textIndent: "2rem",
    color: "#0c0f0a",
  },
  footer: {
    backgroundColor: "#0c0f0a",
    fontSize: "1.2rem",
    textAlign: "center",
    padding: theme.spacing(3, 0),
    color: "#e0fbfc",
  },
}));

export default function RecipeReviewCard() {
  const classes = useStyles();
  const [t] = useTranslation("global");
  return (
    <React.Fragment>
      <Typography variant="h2" color="secondary" className={classes.titulo}>
        Study
      </Typography>
      <Typography
        id={"misEstudios"}
        variant="h5"
        color="secondary"
        className={classes.subtitulo}
      >
        Professional
      </Typography>
      <Grid container className={classes.root}>
        <Grid item xs={12} sm={8} className={classes.item}>
          <Card className={classes.card}>
            <CardHeader
              data-aos="flip-up"
              data-aos-duration="2000"
              className={classes.avatar}
              avatar={
                <Avatar aria-label="recipe">
                  <img src={uvm} alt="Foto" className={classes.avatar} />
                </Avatar>
              }
              title={t("Presentación.UNIVERSIDAD")}
              subheader="2016 - 2020"
            />

            <CardContent>
              <Typography
                variant="h5"
                color="secondary"
                className={classes.subtitulo1}
              >
                {t("Presentación.Ingeniero")}
              </Typography>
              <Typography className={classes.parrafo} color="primary">
                {t("Presentación.Estudios")}
              </Typography>
            </CardContent>
            <CardActions disableSpacing>
              <IconButton
                aria-label="share"
                href={"http://www.uvm.edu.ve/"}
                target="_blank"
                color="secondary"
              >
                <ShareIcon />
              </IconButton>
            </CardActions>
          </Card>
        </Grid>
      </Grid>
      <footer className={classes.footer}>
        {t("Presentación.Derecho")} {new Date().getFullYear()}
      </footer>
    </React.Fragment>
  );
}
